changeSet.sql:
ALTER TABLE cashier_billable_service ADD COLUMN IF NOT EXISTS retired BOOLEAN DEFAULT FALSE NOT NULL;
ALTER TABLE cashier_billable_service ADD COLUMN IF NOT EXISTS retired_by INT;
ALTER TABLE cashier_billable_service ADD COLUMN IF NOT EXISTS date_retired DATETIME;
ALTER TABLE cashier_billable_service ADD COLUMN IF NOT EXISTS retire_reason VARCHAR(255);
ALTER TABLE cashier_item_price ADD COLUMN IF NOT EXISTS retired BOOLEAN DEFAULT FALSE NOT NULL;
ALTER TABLE cashier_item_price ADD COLUMN IF NOT EXISTS retired_by INT;
ALTER TABLE cashier_item_price ADD COLUMN IF NOT EXISTS date_retired DATETIME;
ALTER TABLE cashier_item_price ADD COLUMN IF NOT EXISTS retire_reason VARCHAR(255);

